# views/checkout_view.py (~30 lines)
class CheckoutView:
    def post(self, request):
        checkout = CheckoutService.process(request.data)
        return Response(CheckoutSerializer(checkout).data)

# services/checkout_service.py (~50 lines)
class CheckoutService:
    @staticmethod
    def process(data: dict) -> Checkout:
        validated = CheckoutValidator.validate(data)
        inventory = InventoryService.reserve(validated.items)
        payment = PaymentService.charge(validated.card, inventory.total)
        order = Order.objects.create(payment=payment)
        events.publish(OrderCreated(order))
        return order

